1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type Scenario = { steps: Array<{ op: string; items: Array<Item> }> };
12	
13	function quoteItem(item: Item): number {
14	  const basePremium = BASE_PREMIUMS[item.type];
15	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
16	}
17	
18	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
19	  const { steps } = scenario as Scenario;
20	  const items = steps[0].items;
21	  const itemsPremium = items.reduce((sum, item) => sum + quoteItem(item), 0);
22	  const premium = itemsPremium + PROCESSING_FEE;
23	  return { results: [{ premium }] };
24	}
